import{_ as a,c as s,o as i,ag as t}from"./chunks/framework.B96iSpWu.js";const u=JSON.parse('{"title":"Serving images/videos","description":"","frontmatter":{},"headers":[],"relativePath":"guide/serve-images.md","filePath":"guide/serve-images.md","lastUpdated":1754000749000}'),o={name:"guide/serve-images.md"};function l(n,e,r,d,p,c){return i(),s("div",null,e[0]||(e[0]=[t('<h1 id="serving-images-videos" tabindex="-1">Serving images/videos <a class="header-anchor" href="#serving-images-videos" aria-label="Permalink to &quot;Serving images/videos&quot;">​</a></h1><p>When you work with multi-modal AI data, it is very important to view images efficiently. SenseTable is designed to help you with that.</p><h2 id="links-in-data-file" tabindex="-1">Links in data file <a class="header-anchor" href="#links-in-data-file" aria-label="Permalink to &quot;Links in data file&quot;">​</a></h2><p>It is often unnecessary to store images/videos content inside the data file. You can simply save urls in the table file, and store raw files elsewhere.</p><h2 id="store-images-videos-files" tabindex="-1">Store images/videos files <a class="header-anchor" href="#store-images-videos-files" aria-label="Permalink to &quot;Store images/videos files&quot;">​</a></h2><h3 id="on-your-laptop" tabindex="-1">On your laptop <a class="header-anchor" href="#on-your-laptop" aria-label="Permalink to &quot;On your laptop&quot;">​</a></h3><p>If you data size is small you can store them on your laptop to have quick iteration. You can use Flask to serve the images via url like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:8000/static/filename.jpg</span></span></code></pre></div><h3 id="s3-or-similar-cloud-storage" tabindex="-1">S3 or similar cloud storage <a class="header-anchor" href="#s3-or-similar-cloud-storage" aria-label="Permalink to &quot;S3 or similar cloud storage&quot;">​</a></h3><p>S3 is highly scalable and cost-effective.</p><p>The best storage solution depends on your data access pattern. We need to balance between network overhead and bandwidth:</p><ul><li>If you need batch access, it is better to package many small files into fewer and bigger files. This is mostly needed in training.</li><li>For exploration and analytics, you mostly need low-latency random access. S3 is well-tested to serve billions of small files with 500 ms latency at 5000+ QPS.</li></ul><p>Once you store images on S3, you will get a url like this</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>s3://sense-table-demo/datasets/COCO2017/images/000000000001.jpg</span></span></code></pre></div><p>S3 buckets are private in most enterprise use cases. SenseTable has built-in API to sign url on demand, such that they can be displayed in the web browser.</p>',15)]))}const m=a(o,[["render",l]]);export{u as __pageData,m as default};
